test.describe('case 68: auto_owner 自动', () => {
  test('product.auto_owner=true: 创建者自动获得 owner 权限', async ({ page }) => {
    await loginAs(page, 'NEW_USER_PRODUCT');
    const r = await page.request.post(`${API_BASE}/api/v1/product`, {
      headers: { 'X-User-Id': 'NEW_USER_PRODUCT' },
      data: { name: 'auto_owner_test', code: 'AOT_ccgys' },
    });
    expect([200, 201]).toContain(r.status());
    if (r.status() === 200 || r.status() === 201) {
      const body = await r.json();
      const newId = body?.data?.id;
      if (newId) {
        // 创建者应能修改自己创建的 (owner 权限)
        const r2 = await callApi(page, 'PUT', '/api/v1/product/' + newId, 'NEW_USER_PRODUCT', { name: 'updated' });
        expect([200, 201]).toContain(r2);
      }
    }
  });

  test('version.auto_owner=true: 创建者自动获得 owner 权限', async ({ page }) => {
    await loginAs(page, 'NEW_USER_VERSION');
    const r = await page.request.post(`${API_BASE}/api/v1/version`, {
      headers: { 'X-User-Id': 'NEW_USER_VERSION' },
      data: { name: 'auto_owner_test', code: 'AOT_zkignws' },
    });
    expect([200, 201]).toContain(r.status());
    if (r.status() === 200 || r.status() === 201) {
      const body = await r.json();
      const newId = body?.data?.id;
      if (newId) {
        // 创建者应能修改自己创建的 (owner 权限)
        const r2 = await callApi(page, 'PUT', '/api/v1/version/' + newId, 'NEW_USER_VERSION', { name: 'updated' });
        expect([200, 201]).toContain(r2);
      }
    }
  });

});



